```typescript
import { setup, assign } from 'xstate';

type Lang = 'ts' | 'py' | 'go' | 'rs';
type Theme = 'light' | 'dark' | 'solarized';

interface Ctx {
  language: Lang;
  theme: Theme;
  tabWidth: number;
  dirty: boolean;
}

type Ev =
  | { type: 'SET_LANG'; value: Lang }
  | { type: 'SET_THEME'; value: Theme }
  | { type: 'SET_TAB'; value: number }
  | { type: 'SAVED' };

export const editorSettingsMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    markDirty: assign({ dirty: () => true }),
    markClean: assign({ dirty: () => false }),
    persist: ({ context }) => {
      // write to storage (side-effect stub)
      void context;
    }
  },
  delays: { PERSIST_AFTER: 750 }
}).createMachine({
  id: 'editorSettings',
  context: { language: 'ts', theme: 'dark', tabWidth: 2, dirty: false },
  initial: 'clean',
  states: {
    clean: {
      on: {
        SET_LANG: { target: 'dirty', actions: [assign({ language: ({ event }) => event.value }), 'markDirty'] },
        SET_THEME: { target: 'dirty', actions: [assign({ theme: ({ event }) => event.value }), 'markDirty'] },
        SET_TAB: { target: 'dirty', actions: [assign({ tabWidth: ({ event }) => event.value }), 'markDirty'] }
      }
    },
    dirty: {
      after: { PERSIST_AFTER: { target: 'clean', actions: ['persist', 'markClean'] } },
      on: {
        SET_LANG: { actions: assign({ language: ({ event }) => event.value }), reenter: true },
        SET_THEME: { actions: assign({ theme: ({ event }) => event.value }), reenter: true },
        SET_TAB: { actions: assign({ tabWidth: ({ event }) => event.value }), reenter: true }
      }
    }
  }
});
```

