interface Ctx { theme: 'light' | 'dark' }
type Ev = { type: 'SET_THEME'; value: 'light' | 'dark' } | { type: 'COMMIT' };

export const settingsDebounce = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: { IDLE: 500 }
