The machine keeps per-language tab width in a record inside context so switching languages restores its preferred tab width instead of resetting to a global default. We store the active language separately and derive current tab width via a helper at read time.

```typescript
import { setup, assign } from 'xstate';

type Lang = 'ts' | 'py' | 'go';
interface Ctx { language: Lang; tabByLang: Record<Lang, number> }
type Ev =
  | { type: 'SWITCH'; lang: Lang }
  | { type: 'SET_TAB'; width: number };

export const perLangTabMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev }
}).createMachine({
  id: 'perLangTab',
  context: { language: 'ts', tabByLang: { ts: 2, py: 4, go: 4 } },
  initial: 'ready',
  states: {
    ready: {
      on: {
        SWITCH: { actions: assign({ language: ({ event }) => event.lang }) },
        SET_TAB: {
          actions: assign({
            tabByLang: ({ context, event }) => ({ ...context.tabByLang, [context.language]: event.width })
          })
        }
      }
    }
  }
});
