```typescript
import { setup, assign } from 'xstate';

interface Device { id: string; name: string }
interface Ctx { devices: Device[]; selected: Device | null; error: string | null }

type Ev =
  | { type: 'SCAN' }
  | { type: 'FOUND'; device: Device }
  | { type: 'SELECT'; id: string }
  | { type: 'PAIR' }
  | { type: 'CONFIRMED' }
  | { type: 'CANCEL' };

export const pairingMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: { PAIR_TIMEOUT: 10000 }
}).createMachine({
  id: 'pairing',
  context: { devices: [], selected: null, error: null },
  initial: 'idle',
  states: {
    idle: { on: { SCAN: 'scanning' } },
    scanning: {
      on: {
        FOUND: {
          actions: assign({ devices: ({ context, event }) => [...context.devices, event.device] })
        },
        SELECT: {
          target: 'discovered',
          actions: assign({
            selected: ({ context, event }) => context.devices.find((d) => d.id === event.id) ?? null
          })
        },
        CANCEL: 'idle'
      }
    },
    discovered: { on: { PAIR: 'pairing', CANCEL: 'idle' } },
    pairing: {
      after: { PAIR_TIMEOUT: { target: 'error', actions: assign({ error: () => 'pairing timed out' }) } },
      on: { CONFIRMED: 'connected', CANCEL: 'idle' }
    },
    connected: { on: { CANCEL: 'idle' } },
    error: { on: { SCAN: { target: 'scanning', actions: assign({ error: () => null }) } } }
  }
});
```

Wrap the scanner as a fromCallback actor that periodically emits FOUND events via sendBack, and return a cleanup function to stop scanning.

```typescript
import { setup, assign, fromCallback } from 'xstate';

interface Device { id: string; name: string }
interface Ctx { devices: Device[] }
type ChildEv = { type: 'FOUND'; device: Device };
type Ev = ChildEv | { type: 'START' } | { type: 'STOP' };

const scanner = fromCallback<Ev>(({ sendBack }) => {
  let n = 0;
  const id = setInterval(() => {
    n += 1;
    sendBack({ type: 'FOUND', device: { id: `dev-${n}`, name: `Speaker ${n}` } });
  }, 500);
  return () => clearInterval(id);
});

export const scanMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { scanner }
}).createMachine({
  id: 'scan',
  context: { devices: [] },
  initial: 'idle',
  states: {
    idle: { on: { START: 'scanning' } },
    scanning: {
      invoke: { src: 'scanner' },
      on: {
        FOUND: { actions: assign({ devices: ({ context, event }) => [...context.devices, event.device] }) },
        STOP: 'idle'
      }
    }
  }
});
```

A pairing timeout is just an after transition from the pairing state to a failure state. Declaring the duration in setup.delays keeps the timing configurable per instance and keeps the state config free of literal numbers.

```typescript
import { setup, assign } from 'xstate';

interface Ctx { deviceId: string | null; error: string | null }
type Ev = { type: 'START'; id: string } | { type: 'OK' } | { type: 'RESET' };

export const pairStep = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: { PAIR_TIMEOUT: 8000 }
}).createMachine({
  id: 'pairStep',
  context: { deviceId: null, error: null },
  initial: 'idle',
  states: {
    idle: { on: { START: { target: 'pairing', actions: assign({ deviceId: ({ event }) => event.id }) } } },
    pairing: {
      after: { PAIR_TIMEOUT: { target: 'failed', actions: assign({ error: () => 'timed out' }) } },
      on: { OK: 'connected' }
    },
    connected: { on: { RESET: 'idle' } },
    failed: { on: { RESET: { target: 'idle', actions: assign({ error: () => null }) } } }
  }
});
```

```typescript
import { setup, assign } from 'xstate';

interface Ctx { attempts: number; error: string | null }
type Ev = { type: 'START' } | { type: 'SUCCESS' } | { type: 'FAIL'; reason: string } | { type: 'CANCEL' };

export const pairingRetry = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    canRetry: ({ context }) => context.attempts < 3,
    exhausted: ({ context }) => context.attempts >= 3
  },
  actions: {
    bump: assign({ attempts: ({ context }) => context.attempts + 1 }),
    recordError: assign({ error: ({ event }) => (event.type === 'FAIL' ? event.reason : null) }),
    reset: assign({ attempts: () => 0, error: () => null })
  }
}).createMachine({
  id: 'pairingRetry',
  context: { attempts: 0, error: null },
  initial: 'idle',
  states: {
    idle: { on: { START: { target: 'pairing', actions: 'reset' } } },
    pairing: {
      entry: 'bump',
      on: {
        SUCCESS: 'connected',
        FAIL: [
          { guard: 'canRetry', target: 'pairing', reenter: true, actions: 'recordError' },
          { guard: 'exhausted', target: 'failed', actions: 'recordError' }
        ],
        CANCEL: 'idle'
      }
    },
    connected: { on: { CANCEL: 'idle' } },
    failed: { on: { START: { target: 'pairing', actions: 'reset' } } }
  }
});
```

