import { setup, assign } from 'xstate';

type Badge = 'profile' | 'tutor' | 'firstAction';
interface Ctx { badges: Badge[] }

type Ev =
  | { type: 'PROFILE_DONE' }
  | { type: 'TUTORIAL_DONE' }
  | { type: 'FIRST_ACTION_DONE' };

export const onboardingMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    award: assign({
      badges: ({ context, event }) => {
        const map: Record<Ev['type'], Badge> = {
          PROFILE_DONE: 'profile',
          TUTORIAL_DONE: 'tutor',
          FIRST_ACTION_DONE: 'firstAction'
        };
        const b = map[event.type];
        return context.badges.includes(b) ? context.badges : [...context.badges, b];
      }
    })
  }
}).createMachine({
  id: 'onboarding',
  context: { badges: [] },
  type: 'parallel',
  states: {
    profile: {
      initial: 'todo',
      states: {
        todo: { on: { PROFILE_DONE: { target: 'done', actions: 'award' } } },
        done: { type: 'final' }
