Each region has its own final state. When all regions reach final, the parent compound state itself emits onDone, which you can use from a wrapping state to target a completed state. The types.output type describes what the machine or a state returns when finalised.

```typescript
import { setup, assign } from 'xstate';

interface Ctx { badges: string[] }
type Ev = { type: 'A' } | { type: 'B' };

export const twoTrack = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: { addBadge: assign({ badges: ({ context, event }) => [...context.badges, event.type] }) }
}).createMachine({
  id: 'twoTrack',
  context: { badges: [] },
  initial: 'running',
  states: {
    running: {
      type: 'parallel',
      onDone: 'completed',
      states: {
        left: {
          initial: 'todo',
          states: {
            todo: { on: { A: { target: 'done', actions: 'addBadge' } } },
            done: { type: 'final' }
          }
        },
        right: {
          initial: 'todo',
          states: {
            todo: { on: { B: { target: 'done', actions: 'addBadge' } } },
            done: { type: 'final' }
          }
        }
      }
    },
    completed: { type: 'final' }
  }
});
```

