import { setup, assign } from 'xstate';

interface Ctx { plan: 'basic' | 'pro'; pastDueAt: number | null }
type Ev =
  | { type: 'SUBSCRIBE'; plan: 'basic' | 'pro' }
  | { type: 'PAYMENT_OK' }
  | { type: 'PAYMENT_FAIL' }
  | { type: 'CANCEL' }
  | { type: 'RESUME' };

export const subscriptionMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: { TRIAL_LEN: 7 * 24 * 60 * 60 * 1000, DUNNING_LEN: 3 * 24 * 60 * 60 * 1000 }
}).createMachine({
  id: 'subscription',
  context: { plan: 'basic', pastDueAt: null },
  initial: 'trial',
  states: {
    trial: {
      after: { TRIAL_LEN: 'active' },
      on: { SUBSCRIBE: { target: 'active', actions: assign({ plan: ({ event }) => event.plan }) }, CANCEL: 'cancelled' }
    },
    active: {
      on: {
        PAYMENT_FAIL: { target: 'pastDue', actions: assign({ pastDueAt: () => Date.now() }) },
        CANCEL: 'cancelled'
