      on: {
        POINTER_DOWN: {
          target: 'drawing',
          actions: assign({ strokes: ({ context, event }) => [...context.strokes, [event.point]] })
        }
      }
    },
    drawing: {
      on: {
        POINTER_MOVE: {
          actions: assign({
            strokes: ({ context, event }) => {
              const next = context.strokes.slice();
              const last = next[next.length - 1] ?? [];
              next[next.length - 1] = [...last, event.point];
