      }
    },
    preview: {
      on: {
        PREVIEW: { actions: assign({ preview: ({ event }) => event.dataUrl }) },
        SAVE: 'saved',
        DISCARD: { target: 'idle', actions: assign({ strokes: () => [], preview: () => null }) }
