  context: { last: null, error: null },
  initial: 'idle',
  states: {
    idle: { on: { REQUEST: 'requesting' } },
    requesting: {
      on: {
        GRANTED: 'tracking',
        DENIED: { target: 'error', actions: assign({ error: ({ event }) => event.reason }) }
      }
    },
    tracking: {
      invoke: { src: 'geoWatcher' },
      on: {
        FIX: { actions: assign({ last: ({ event }) => event.fix }) },
        GEO_ERR: { target: 'error', actions: assign({ error: ({ event }) => event.reason }) },
        PAUSE: 'paused'
      }
    },
    paused: { on: { RESUME: 'tracking' } },
    error: { on: { REQUEST: { target: 'requesting', actions: assign({ error: () => null }) } } }
  }
});
```

Use fromCallback to register watchPosition, forward typed events via sendBack, and return clearWatch as the cleanup.

```typescript
import { setup, fromCallback } from 'xstate';

type Ev = { type: 'POS'; lat: number; lng: number } | { type: 'ERR'; reason: string };

const geoActor = fromCallback<Ev>(({ sendBack }) => {
  const id = navigator.geolocation.watchPosition(
    (p) => sendBack({ type: 'POS', lat: p.coords.latitude, lng: p.coords.longitude }),
    (e) => sendBack({ type: 'ERR', reason: e.message })
  );
  return () => navigator.geolocation.clearWatch(id);
});

export const geoSkeleton = setup({
  types: { events: {} as Ev },
  actors: { geoActor }
}).createMachine({
  id: 'geoSkeleton',
  initial: 'watching',
  states: {
    watching: { invoke: { src: 'geoActor' }, on: { POS: {}, ERR: 'failed' } },
    failed: { type: 'final' }
  }
});
```

The machine enters a requesting state that awaits GRANTED or DENIED. A DENIED event carries a reason, which the machine assigns into context.error and transitions to a terminal-ish error state the UI can render. Retry is a REQUEST event that clears the error on entry of requesting.

```typescript
import { setup, assign } from 'xstate';

interface Ctx { error: string | null }
type Ev = { type: 'REQUEST' } | { type: 'GRANTED' } | { type: 'DENIED'; reason: string };

export const permFlow = setup({
  types: { context: {} as Ctx, events: {} as Ev }
}).createMachine({
  id: 'permFlow',
  context: { error: null },
  initial: 'idle',
  states: {
    idle: { on: { REQUEST: { target: 'requesting', actions: assign({ error: () => null }) } } },
    requesting: {
      on: {
        GRANTED: 'granted',
        DENIED: { target: 'denied', actions: assign({ error: ({ event }) => event.reason }) }
      }
    },
    granted: {},
    denied: { on: { REQUEST: { target: 'requesting', actions: assign({ error: () => null }) } } }
  }
});
```
